<?php namespace App\Repositories\Academic;use App\Repositories\BaseRepository;use App\Models\Academic\Homework;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class HomeworkRepository extends BaseRepository{    public function __construct(Homework $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function findByTeacher(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('homework_date', $date)->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('homework_date', [$startDate, $endDate])->get();    }    public function getPendingHomework(): Collection    {        return $this->query()->where('submission_date', '>=', now())->orderBy('submission_date', 'asc')->get();    }    public function getOverdueHomework(): Collection    {        return $this->query()->where('submission_date', '<', now())->get();    }    public function searchHomework(string $keyword): Collection    {        return $this->query()->where('title', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getByClassAndSection(int $classId, int $sectionId): Collection    {        return $this->query()->where('class_id', $classId)->where('section_id', $sectionId)->orderBy('homework_date', 'desc')->get();    }}